INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'eb8861f1-eedc-4f91-81e1-fef612da36db',
  '00000000-0000-0000-0000-000000000001',
  $escape$LangChain RAG — Chunking, MMR Retrieval, and Reranking That Actually Works$escape$,
  $escape$Chunking strategy is the most undertuned part of LangChain RAG pipelines. The default `RecursiveCharacterTextSplitter` splits on `["\n\n", "\n", " "]` with `chunk_size=1000, chunk_overlap=200` — reasonable, but semantically blind. For better coherence, swap to `SemanticChunker` from `langchain_experimental.text_splitter`, which uses embedding cosine similarity to detect topic boundaries before splitting.

For retrieval, drop plain similarity search. Use `search_type="mmr"` on `.as_retriever()` to apply Maximal Marginal Relevance — set `fetch_k` high (50+) and `k` low (10–20) so MMR has candidates to diversify over. This prevents the retriever from surfacing near-duplicate chunks that bloat context and confuse the LLM.

Reranking is the single highest-leverage postprocessing step. Wrap any retriever with `ContextualCompressionRetriever` + `CohereRerank` (or the free `FlashrankRerank` from `langchain_community.document_compressors`). A cross-encoder rescores the top-k candidates against the actual query, not just approximate vector distance. In practice this boosts answer quality 15–30% without touching your vector store, embeddings, or prompt.$escape$,
  $escape$from langchain.retrievers import ContextualCompressionRetriever
from langchain.retrievers.document_compressors import CohereRerank
from langchain_community.vectorstores import Chroma
from langchain_openai import OpenAIEmbeddings

vectorstore = Chroma(embedding_function=OpenAIEmbeddings())
base_retriever = vectorstore.as_retriever(
    search_type="mmr",
    search_kwargs={"k": 10, "fetch_k": 50}
)
compressor = CohereRerank(model="rerank-english-v3.0", top_n=5)
retriever = ContextualCompressionRetriever(
    base_compressor=compressor, base_retriever=base_retriever
)
docs = retriever.invoke("How does RLHF work?")$escape$,
  $escape$python$escape$,
