INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1c0b9e03-fe76-4ab5-b7cf-a8d016ad5d57',
  '00000000-0000-0000-0000-000000000001',
  $escape$LangChain + Claude — System Prompts, Tool Use, and Streaming in One Chain$escape$,
  $escape$LangChain's `ChatAnthropic` integration exposes the full Claude API surface directly in your chains. System prompts are passed via `SystemMessage` — not as a constructor param — keeping them composable with `ChatPromptTemplate`. For tool use, bind tools with `.bindTools([...])` on the `ChatAnthropic` instance; LangChain handles the `tool_use` / `tool_result` message cycle automatically when you wire an `AgentExecutor` or use `createToolCallingAgent`. Streaming works out of the box with `.stream()` or `.streamEvents()` — the latter gives you granular chunk-level visibility including `on_llm_stream` events, useful for token-level UI updates. Model selection matters: `claude-opus-4-5` for complex reasoning chains, `claude-haiku-4-5-20251001` for high-throughput tool-heavy agents. Watch the `max_tokens` param — Claude requires it explicitly, unlike OpenAI models. Set it on the `ChatAnthropic` constructor or you'll hit a 400. For cost control in multi-turn agents, use `trim_messages` from `langchain_core.messages` to prune history before each invocation.$escape$,
  $escape$from langchain_anthropic import ChatAnthropic
from langchain_core.messages import SystemMessage, HumanMessage
from langchain_core.tools import tool

@tool
def get_repo_stars(repo: str) -> int:
    """Returns star count for a GitHub repo."""
    return 42000

llm = ChatAnthropic(model="claude-opus-4-5", max_tokens=1024)
llm_with_tools = llm.bindTools([get_repo_stars])

messages = [
    SystemMessage(content="You are a concise developer assistant."),
    HumanMessage(content="How many stars does langchain have?")
]

for chunk in llm_with_tools.stream(messages):
    print(chunk.content, end="", flush=True)$escape$,
  $escape$python$escape$,
