INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '272cb1aa-dbcb-48c1-98d8-2e5586cecb62',
  '00000000-0000-0000-0000-000000000001',
  $escape$LangChain + Groq — Sub-Second LLM Inference Without Changing Your Chain Logic$escape$,
  $escape$Groq's LPU (Language Processing Unit) delivers 500–800 tokens/sec on models like `llama-3.3-70b-versatile` — roughly 10–25x faster than GPU-hosted equivalents. LangChain exposes this through `ChatGroq` in the `langchain-groq` package, which is a drop-in replacement for `ChatOpenAI`. Because `ChatGroq` implements the same `BaseChatModel` interface, any chain, agent, or LCEL expression that accepts a chat model works without modification.

Supported models include `llama-3.3-70b-versatile`, `llama-3.1-8b-instant`, `mixtral-8x7b-32768`, and `gemma2-9b-it`. Groq's API is OpenAI-compatible at the wire level, but prefer `ChatGroq` over monkey-patching `ChatOpenAI` with a custom `base_url` — the dedicated class handles rate-limit retries and Groq-specific response fields correctly.

For latency-sensitive pipelines — streaming chat, real-time RAG, or tool-calling agents — swap the model reference and gain speed with zero chain refactoring. `ChatGroq` supports `streaming=True` and `bind_tools()`, so existing ReAct agents work as-is.$escape$,
  $escape$from langchain_groq import ChatGroq
from langchain_core.prompts import ChatPromptTemplate

llm = ChatGroq(
    model="llama-3.3-70b-versatile",
    temperature=0,
    streaming=True,
    max_tokens=1024,
)

prompt = ChatPromptTemplate.from_messages([
    ("system", "You are a concise technical assistant."),
    ("human", "{question}"),
])

chain = prompt | llm

for chunk in chain.stream({"question": "Explain GGUF quantization in 3 sentences."}):
    print(chunk.content, end="", flush=True)$escape$,
